  1	import {
  2	  type ChangeEvent,
  3	  type DetailedHTMLProps,
  4	  type FC,
  5	  type HTMLAttributes,
  6	  type ReactNode,
  7	  useState,
  8	} from 'react';
  9	import TagsInput from 'react-tagsinput';
 10	
 11	import ModalForm from '@components/ModalForm/ModalForm';
 12	import type { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk';
 13	import { Stack, StackItem } from '@patternfly/react-core';
 14	import { isEmpty } from '@utils/helpers';
 15	import { useForkliftTranslation } from '@utils/i18n';
 16	
 17	import { LABELS_MODAL_DESCRIPTION } from './utils/constants';
 18	import { isLabelValid } from './utils/isLabelValid';
 19	import { labelsArrayToObject } from './utils/labelsArrayToObject';
 20	import { labelsToArray } from './utils/labelsToArray';
 21	import { renderTag } from './utils/renderTag';
 22	
 23	import './LabelsModal.scss';
 24	
 25	// console is declaring a new html element for some reason, we have to copy it for css reasons.
 26	declare global {
 27	  // eslint-disable-next-line @typescript-eslint/no-namespace
 28	  namespace JSX {
 29	    // eslint-disable-next-line @typescript-eslint/consistent-type-definitions
 30	    interface IntrinsicElements {
 31	      'tags-input': DetailedHTMLProps<HTMLAttributes<HTMLElement>, HTMLElement>;
 32	    }
 33	  }
 34	}
 35	
 36	type LabelsModalProps = {
 37	  initialLabels?: Record<string, string>;
 38	  description?: ReactNode;
 39	  title?: string;
 40	  onConfirm: (labels: Record<string, string | null>) => Promise<K8sResourceCommon>;
 41	};
 42	
 43	const LabelsModal: FC<LabelsModalProps> = ({ description, initialLabels, onConfirm, title }) => {
 44	  const { t } = useForkliftTranslation();
 45	  const [inputValue, setInputValue] = useState('');
 46	  const [isInputValid, setIsInputValid] = useState(true);
 47	  const [labels, setLabels] = useState<string[]>(
 48	    labelsToArray(isEmpty(initialLabels) ? {} : initialLabels),
 49	  );
 50	
 51	  // Keys that add tags: Enter
 52	  const addKeys = [13];
 53	  // Backspace deletes tags, but not if there is text being edited in the input field
 54	  const removeKeys = inputValue.length ? [] : [8];
 55	
 56	  const onInputChange = (e: ChangeEvent<HTMLInputElement>) => {
 57	    const { value } = e.target;
 58	
 59	    if (value === '') {
 60	      setInputValue(value);
 61	      setIsInputValid(true);
 62	      return;
 63	    }
 64	    setInputValue(value);
 65	    setIsInputValid(isLabelValid(value));
 66	  };
 67	
 68	  const inputProps = {
 69	    autoFocus: true,
 70	    className: 'input'.concat(isInputValid ? '' : ' invalid-tag'),
 71	    onChange: onInputChange,
 72	    placeholder: isEmpty(labels) ? 'key=value' : '',
 73	    spellCheck: 'false',
 74	    value: inputValue,
 75	  };
 76	
 77	  const handleLabelsChange = (newLabels: string[], changed: string[]) => {
 78	    const { 0: newLabel } = changed;
 79	
 80	    if (!isLabelValid(newLabel)) {
 81	      setIsInputValid(false);
 82	      return;
 83	    }
 84	
 85	    // duplicate labels
 86	    if (newLabels.filter((label) => label === newLabel).length > 1) {
 87	      setIsInputValid(false);
 88	      return;
 89	    }
 90	
 91	    // if key exists, overwrite value
 92	    if (newLabels.filter((label) => label.split('=')[0] === newLabel.split('=')[0]).length > 1) {
 93	      const filteredLabels = newLabels.filter(
 94	        (label) => label.split('=')[0] !== newLabel.split('=')[0],
 95	      );
 96	      setLabels([...filteredLabels, newLabel]);
 97	      setInputValue('');
 98	      return;
 99	    }
100	
101	    setLabels(newLabels);
102	    setInputValue('');
103	  };
104	
105	  return (
106	    <ModalForm
107	      testId="labels-modal"
108	      title={title ?? t('Edit labels')}
109	      onConfirm={async () => onConfirm(labelsArrayToObject(labels)) ?? {}}
110	    >
111	      <Stack hasGutter>
112	        <StackItem>{description ?? LABELS_MODAL_DESCRIPTION}</StackItem>
113	        <StackItem>
114	          <div className="forklift-labels-modal-body">
115	            <tags-input>
116	              <TagsInput
117	                addKeys={addKeys}
118	                removeKeys={removeKeys}
119	                addOnBlur
120	                className="tags"
121	                inputProps={inputProps}
122	                onChange={handleLabelsChange}
123	                renderTag={renderTag}
124	                value={labels}
125	              />
126	            </tags-input>
127	          </div>
128	        </StackItem>
129	      </Stack>
130	    </ModalForm>
131	  );
132	};
133	
134	export default LabelsModal;

