 1	import { Label } from '@patternfly/react-core';
 2	
 3	export const renderTag = (props: {
 4	  tag: string;
 5	  key: string;
 6	  onRemove: (key: string) => void;
 7	  getTagDisplayValue: (tag: string) => string;
 8	}) => {
 9	  const { getTagDisplayValue, key, onRemove, tag } = props;
10	
11	  return (
12	    <Label
13	      className={'co-label tag-item-content'}
14	      key={key}
15	      onClose={() => {
16	        onRemove(key);
17	      }}
18	    >
19	      {getTagDisplayValue(tag)}
20	    </Label>
21	  );
22	};

